@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;700&family=Bebas+Neue&family=Inter:wght@400;500;600&display=swap');

  :root {
    --bg:        oklch(0.11 0.015 252);
    --bg2:       oklch(0.15 0.015 252);
    --bg3:       oklch(0.19 0.015 252);
    --gold:      oklch(0.76 0.18 80);
    --gold-dim:  oklch(0.55 0.14 80);
    --navy:      oklch(0.27 0.09 248);
    --text:      oklch(0.91 0.01 252);
    --muted:     oklch(0.55 0.02 252);
    --green:     oklch(0.72 0.17 155);
    --border:    oklch(0.22 0.02 252);
    --font-mono: 'JetBrains Mono', monospace;
    --font-disp: 'Bebas Neue', sans-serif;
    --font-body: 'Inter', sans-serif;
  }
  *, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

  html { scroll-behavior: smooth; }

  body {
    background: var(--bg);
    color: var(--text);
    font-family: var(--font-body);
    line-height: 1.6;
    overflow-x: hidden;
  }

  /* ── SCANLINE OVERLAY ── */
  body::before {
    content: '';
    position: fixed; inset: 0;
    background: repeating-linear-gradient(
      0deg,
      transparent,
      transparent 2px,
      oklch(0 0 0 / 0.04) 2px,
      oklch(0 0 0 / 0.04) 4px
    );
    pointer-events: none;
    z-index: 9999;
  }

  /* ── NAV ── */
  nav {
    position: fixed; top: 0; left: 0; right: 0;
    z-index: 100;
    display: flex; align-items: center; justify-content: space-between;
    padding: 0 2.5rem;
    height: 60px;
    background: oklch(0.11 0.015 252 / 0.92);
    backdrop-filter: blur(12px);
    border-bottom: 1px solid var(--border);
  }
  .nav-logo {
    font-family: var(--font-disp);
    font-size: 1.4rem;
    letter-spacing: 0.04em;
    color: var(--gold);
    text-decoration: none;
  }
  .nav-logo span { color: var(--text); }
  .nav-links {
    display: flex; gap: 2rem; list-style: none;
  }
  .nav-links a {
    font-family: var(--font-mono);
    font-size: 0.78rem;
    color: var(--muted);
    text-decoration: none;
    letter-spacing: 0.06em;
    text-transform: uppercase;
    transition: color 0.2s;
  }
  .nav-links a:hover, .nav-links a.active { color: var(--gold); }

  /* ── HERO ── */
  #hero {
    min-height: 100vh;
    display: grid;
    place-items: center;
    padding: 80px 2rem 2rem;
    position: relative;
    overflow: hidden;
  }
  .hero-bg-grid {
    position: absolute; inset: 0;
    background-image:
      linear-gradient(var(--border) 1px, transparent 1px),
      linear-gradient(90deg, var(--border) 1px, transparent 1px);
    background-size: 48px 48px;
    opacity: 0.4;
    mask-image: radial-gradient(ellipse 80% 80% at 50% 50%, black 30%, transparent 100%);
  }
  .hero-glow {
    position: absolute;
    width: 600px; height: 600px;
    background: radial-gradient(circle, oklch(0.55 0.14 80 / 0.12) 0%, transparent 70%);
    top: 50%; left: 50%;
    transform: translate(-50%, -55%);
    pointer-events: none;
  }
  .hero-inner {
    position: relative;
    display: flex;
    flex-direction: column;
    align-items: center;
    text-align: center;
    gap: 1.5rem;
    max-width: 860px;
  }
  .hero-logo-wrap {
    width: 300px; height: 300px;
    border-radius: 50%;
    overflow: hidden;
    border: 3px solid var(--gold);
    box-shadow: 0 0 40px oklch(0.76 0.18 80 / 0.3), 0 0 80px oklch(0.76 0.18 80 / 0.1);
    flex-shrink: 0;
    animation: pulse-glow 3s ease-in-out infinite;
    background: #000;
  }
  @keyframes pulse-glow {
    0%, 100% { box-shadow: 0 0 40px oklch(0.76 0.18 80 / 0.3), 0 0 80px oklch(0.76 0.18 80 / 0.1); }
    50%       { box-shadow: 0 0 60px oklch(0.76 0.18 80 / 0.5), 0 0 120px oklch(0.76 0.18 80 / 0.2); }
  }
  .hero-logo-wrap img {
    width: 100%; height: 100%;
    object-fit: contain;
    object-position: center center;
    transform: scale(0.98);
  }
  .hero-tag {
    font-family: var(--font-mono);
    font-size: 0.75rem;
    color: var(--green);
    letter-spacing: 0.12em;
    text-transform: uppercase;
  }
  .hero-tag::before { content: '> '; }
  .hero-heading {
    font-family: var(--font-disp);
    font-size: clamp(3.5rem, 8vw, 7rem);
    line-height: 0.92;
    letter-spacing: 0.02em;
    color: var(--text);
  }
  .hero-heading .accent { color: var(--gold); }
  .hero-tagline {
    font-family: var(--font-mono);
    font-size: clamp(0.9rem, 2vw, 1.15rem);
    color: var(--muted);
    max-width: 500px;
  }
  .hero-tagline .cursor {
    display: inline-block;
    width: 2px; height: 1.1em;
    background: var(--gold);
    vertical-align: text-bottom;
    animation: blink 0.9s step-end infinite;
  }
  @keyframes blink { 50% { opacity: 0; } }

  .hero-cta {
    display: flex; gap: 1rem; flex-wrap: wrap; justify-content: center;
    margin-top: 0.5rem;
  }
  .btn {
    display: inline-block;
    padding: 0.65rem 1.6rem;
    font-family: var(--font-mono);
    font-size: 0.78rem;
    letter-spacing: 0.08em;
    text-transform: uppercase;
    text-decoration: none;
    border-radius: 3px;
    cursor: pointer;
    transition: all 0.2s;
    border: none;
  }
  .btn-primary {
    background: var(--gold);
    color: oklch(0.11 0.015 252);
    font-weight: 700;
  }
  .btn-primary:hover { background: oklch(0.82 0.18 80); transform: translateY(-2px); }
  .btn-outline {
    background: transparent;
    color: var(--gold);
    border: 1px solid var(--gold);
  }
  .btn-outline:hover { background: oklch(0.76 0.18 80 / 0.1); transform: translateY(-2px); }

  .hero-stats {
    display: flex; gap: 3rem; margin-top: 1rem;
  }
  .stat { text-align: center; }
  .stat-val {
    font-family: var(--font-disp);
    font-size: 2.2rem;
    color: var(--gold);
    line-height: 1;
  }
  .stat-label {
    font-family: var(--font-mono);
    font-size: 0.65rem;
    color: var(--muted);
    letter-spacing: 0.1em;
    text-transform: uppercase;
    margin-top: 2px;
  }

  /* ── SECTION COMMON ── */
  section { padding: 6rem 2rem; }
  .section-inner { max-width: 1100px; margin: 0 auto; }
  .section-label {
    font-family: var(--font-mono);
    font-size: 0.72rem;
    color: var(--green);
    letter-spacing: 0.14em;
    text-transform: uppercase;
    margin-bottom: 0.5rem;
  }
  .section-label::before { content: '// '; }
  .section-title {
    font-family: var(--font-disp);
    font-size: clamp(2.5rem, 5vw, 4rem);
    letter-spacing: 0.02em;
    line-height: 1;
    margin-bottom: 3rem;
  }
  .section-title .accent { color: var(--gold); }

  /* ── ABOUT ── */
  #about { background: var(--bg2); }
  .about-grid {
    display: grid;
    grid-template-columns: 1fr 1.3fr;
    gap: 4rem;
    align-items: center;
  }
  .about-terminal {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    overflow: hidden;
    font-family: var(--font-mono);
    font-size: 0.82rem;
  }
  .term-bar {
    background: var(--bg3);
    padding: 0.6rem 1rem;
    display: flex; align-items: center; gap: 0.5rem;
    border-bottom: 1px solid var(--border);
  }
  .term-dot { width: 10px; height: 10px; border-radius: 50%; }
  .term-dot.r { background: oklch(0.55 0.2 25); }
  .term-dot.y { background: oklch(0.75 0.2 90); }
  .term-dot.g { background: oklch(0.65 0.2 140); }
  .term-title { font-size: 0.7rem; color: var(--muted); margin-left: auto; margin-right: auto; }
  .term-body { padding: 1.5rem; line-height: 2; }
  .term-line { display: block; }
  .term-prompt { color: var(--green); }
  .term-cmd { color: var(--text); }
  .term-out { color: var(--muted); padding-left: 0.5rem; }
  .term-key { color: var(--gold); }
  .term-blank { display: block; height: 0.8rem; }

  .about-text h3 {
    font-family: var(--font-disp);
    font-size: 2rem;
    color: var(--text);
    margin-bottom: 1rem;
  }
  .about-text p {
    color: var(--muted);
    margin-bottom: 1rem;
    font-size: 0.97rem;
    line-height: 1.75;
  }
  .about-text p strong { color: var(--text); font-weight: 600; }
  .about-text p .shout { color: var(--gold); font-style: italic; }

  /* ── SKILLS ── */
  #skills { background: var(--bg); }
  .skills-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
    gap: 1.5rem;
  }
  .skill-card {
    background: var(--bg2);
    border: 1px solid var(--border);
    border-radius: 6px;
    padding: 1.5rem;
    transition: border-color 0.2s, transform 0.2s;
  }
  .skill-card:hover {
    border-color: var(--gold-dim);
    transform: translateY(-3px);
  }
  .skill-header {
    display: flex; justify-content: space-between; align-items: center;
    margin-bottom: 1rem;
  }
  .skill-name {
    font-family: var(--font-mono);
    font-size: 0.9rem;
    color: var(--text);
    font-weight: 700;
  }
  .skill-pct {
    font-family: var(--font-mono);
    font-size: 0.75rem;
    color: var(--gold);
  }
  .skill-bar-bg {
    height: 6px;
    background: var(--bg3);
    border-radius: 3px;
    overflow: hidden;
  }
  .skill-bar-fill {
    height: 100%;
    background: linear-gradient(90deg, var(--gold-dim), var(--gold));
    border-radius: 3px;
    width: 0%;
    transition: width 1.2s cubic-bezier(0.4,0,0.2,1);
  }
  .skill-desc {
    margin-top: 0.75rem;
    font-size: 0.78rem;
    color: var(--muted);
    font-family: var(--font-mono);
    line-height: 1.5;
  }

  /* ── PROJECTS ── */
  #projects { background: var(--bg2); }
  .projects-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
    gap: 1.5rem;
  }
  .project-card {
    background: var(--bg);
    border: 1px solid var(--border);
    border-radius: 6px;
    overflow: hidden;
    transition: border-color 0.2s, transform 0.2s, box-shadow 0.2s;
    cursor: pointer;
    display: flex; flex-direction: column;
  }
  .project-card:hover {
    border-color: var(--gold-dim);
    transform: translateY(-4px);
    box-shadow: 0 12px 40px oklch(0 0 0 / 0.4);
  }
  .project-thumb {
    height: 180px;
    background: var(--bg3);
    display: flex; align-items: center; justify-content: center;
    border-bottom: 1px solid var(--border);
    font-family: var(--font-mono);
    font-size: 0.72rem;
    color: var(--muted);
    position: relative;
    overflow: hidden;
  }
  .project-thumb-label {
    position: absolute;
    font-size: 0.68rem;
    color: var(--muted);
    letter-spacing: 0.05em;
    z-index: 1;
  }
  /* Mini chart decorations per project */
  .chart-bars {
    display: flex; align-items: flex-end; gap: 5px;
    opacity: 0.35;
  }
  .chart-bars span {
    width: 18px;
    background: linear-gradient(180deg, var(--gold), var(--gold-dim));
    border-radius: 2px 2px 0 0;
    transition: height 0.3s;
  }
  .project-card:hover .chart-bars span { opacity: 0.8; }

  .project-body { padding: 1.5rem; flex: 1; display: flex; flex-direction: column; gap: 0.75rem; }
  .project-tags {
    display: flex; flex-wrap: wrap; gap: 0.4rem;
  }
  .tag {
    font-family: var(--font-mono);
    font-size: 0.65rem;
    padding: 0.2rem 0.55rem;
    background: var(--bg3);
    border: 1px solid var(--border);
    border-radius: 2px;
    color: var(--muted);
    letter-spacing: 0.05em;
    text-transform: uppercase;
  }
  .tag.gold { border-color: var(--gold-dim); color: var(--gold); }
  .project-title {
    font-family: var(--font-disp);
    font-size: 1.6rem;
    letter-spacing: 0.02em;
    color: var(--text);
    line-height: 1.1;
  }
  .project-desc {
    font-size: 0.88rem;
    color: var(--muted);
    line-height: 1.65;
    flex: 1;
  }
  .project-footer {
    display: flex; align-items: center; justify-content: space-between;
    margin-top: 0.5rem;
    padding-top: 1rem;
    border-top: 1px solid var(--border);
    font-family: var(--font-mono);
    font-size: 0.72rem;
    color: var(--muted);
  }
  .project-link {
    color: var(--gold);
    text-decoration: none;
    letter-spacing: 0.05em;
    transition: opacity 0.2s;
  }
  .project-link:hover { opacity: 0.7; }

  /* ── CONTACT ── */
  #contact { background: var(--bg); text-align: center; }
  .contact-inner { max-width: 600px; margin: 0 auto; }
  .contact-inner p {
    color: var(--muted);
    font-size: 0.97rem;
    line-height: 1.75;
    margin-bottom: 2rem;
    font-family: var(--font-mono);
  }
  .contact-inner p .shout { color: var(--gold); }

  /* ── FOOTER ── */
  footer {
    background: var(--bg2);
    border-top: 1px solid var(--border);
    padding: 2rem;
    text-align: center;
    font-family: var(--font-mono);
    font-size: 0.72rem;
    color: var(--muted);
  }
  footer span { color: var(--gold); }

  /* ── SCROLLBAR ── */
  ::-webkit-scrollbar { width: 6px; }
  ::-webkit-scrollbar-track { background: var(--bg); }
  ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
  ::-webkit-scrollbar-thumb:hover { background: var(--gold-dim); }

  /* ── TWEAKS PANEL ── */
  #tweaks-panel {
    position: fixed; bottom: 1.5rem; right: 1.5rem;
    z-index: 200;
    background: var(--bg2);
    border: 1px solid var(--border);
    border-radius: 8px;
    width: 280px;
    box-shadow: 0 20px 60px oklch(0 0 0 / 0.5);
    display: none;
    overflow: hidden;
    font-family: var(--font-mono);
    font-size: 0.8rem;
  }
  #tweaks-panel.open { display: block; }
  .tweaks-header {
    display: flex; justify-content: space-between; align-items: center;
    padding: 0.85rem 1rem;
    background: var(--bg3);
    border-bottom: 1px solid var(--border);
    font-weight: 700; color: var(--gold);
    letter-spacing: 0.08em; font-size: 0.75rem; text-transform: uppercase;
  }
  .tweaks-close { cursor: pointer; color: var(--muted); font-size: 1.1rem; line-height: 1; background: none; border: none; }
  .tweaks-close:hover { color: var(--text); }
  .tweaks-body { padding: 1rem; display: flex; flex-direction: column; gap: 1rem; }
  .tweak-row { display: flex; flex-direction: column; gap: 0.4rem; }
  .tweak-label { color: var(--muted); font-size: 0.7rem; letter-spacing: 0.06em; text-transform: uppercase; }
  .tweak-select, .tweak-input {
    background: var(--bg); border: 1px solid var(--border);
    color: var(--text); padding: 0.4rem 0.6rem;
    border-radius: 3px; font-family: var(--font-mono); font-size: 0.78rem;
    width: 100%; outline: none;
  }
  .tweak-select:focus, .tweak-input:focus { border-color: var(--gold-dim); }

  /* ── RESPONSIVE ── */
  @media (max-width: 700px) {
    .about-grid { grid-template-columns: 1fr; }
    .hero-stats { gap: 1.5rem; }
    .nav-links { display: none; }
  }

  /* ── ANIMATE IN ── */
  .fade-up {
    opacity: 0;
    transform: translateY(24px);
    transition: opacity 0.6s ease, transform 0.6s ease;
  }
  .fade-up.visible { opacity: 1; transform: none; }

/* ── OMYA SHARED STYLES ── */
@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;700&family=Bebas+Neue&family=Inter:wght@400;500;600&display=swap');

:root {
  --bg:        oklch(0.11 0.015 252);
  --bg2:       oklch(0.15 0.015 252);
  --bg3:       oklch(0.19 0.015 252);
  --gold:      oklch(0.76 0.18 80);
  --gold-dim:  oklch(0.55 0.14 80);
  --navy:      oklch(0.27 0.09 248);
  --text:      oklch(0.91 0.01 252);
  --muted:     oklch(0.55 0.02 252);
  --green:     oklch(0.72 0.17 155);
  --border:    oklch(0.22 0.02 252);
  --font-mono: 'JetBrains Mono', monospace;
  --font-disp: 'Bebas Neue', sans-serif;
  --font-body: 'Inter', sans-serif;
  --max-w:     1100px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }

body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font-body);
  line-height: 1.6;
  overflow-x: hidden;
}

/* Scanlines */
body::before {
  content: '';
  position: fixed; inset: 0;
  background: repeating-linear-gradient(0deg, transparent, transparent 2px, oklch(0 0 0 / 0.04) 2px, oklch(0 0 0 / 0.04) 4px);
  pointer-events: none;
  z-index: 9999;
}

/* Nav */
nav {
  position: fixed; top: 0; left: 0; right: 0; z-index: 100;
  display: flex; align-items: center; justify-content: space-between;
  padding: 0 2.5rem; height: 60px;
  background: oklch(0.11 0.015 252 / 0.92);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border);
}
.nav-logo { font-family: var(--font-disp); font-size: 1.4rem; letter-spacing: 0.04em; color: var(--gold); text-decoration: none; }
.nav-logo span { color: var(--text); }
.nav-links { display: flex; gap: 2rem; list-style: none; }
.nav-links a { font-family: var(--font-mono); font-size: 0.78rem; color: var(--muted); text-decoration: none; letter-spacing: 0.06em; text-transform: uppercase; transition: color 0.2s; }
.nav-links a:hover, .nav-links a.active { color: var(--gold); }

/* Page shell */
.page-wrap { padding-top: 60px; min-height: 100vh; }

/* Section */
.section { padding: 5rem 2rem; }
.section-inner { max-width: var(--max-w); margin: 0 auto; }
.section-label { font-family: var(--font-mono); font-size: 0.72rem; color: var(--green); letter-spacing: 0.14em; text-transform: uppercase; margin-bottom: 0.5rem; }
.section-label::before { content: '// '; }
.section-title { font-family: var(--font-disp); font-size: clamp(2.5rem, 5vw, 4rem); letter-spacing: 0.02em; line-height: 1; margin-bottom: 2.5rem; }
.section-title .accent { color: var(--gold); }

/* Buttons */
.btn { display: inline-block; padding: 0.65rem 1.6rem; font-family: var(--font-mono); font-size: 0.78rem; letter-spacing: 0.08em; text-transform: uppercase; text-decoration: none; border-radius: 3px; cursor: pointer; transition: all 0.2s; border: none; }
.btn-primary { background: var(--gold); color: oklch(0.11 0.015 252); font-weight: 700; }
.btn-primary:hover { background: oklch(0.82 0.18 80); transform: translateY(-2px); }
.btn-outline { background: transparent; color: var(--gold); border: 1px solid var(--gold); }
.btn-outline:hover { background: oklch(0.76 0.18 80 / 0.1); transform: translateY(-2px); }

/* Tags */
.tag { font-family: var(--font-mono); font-size: 0.65rem; padding: 0.2rem 0.55rem; background: var(--bg3); border: 1px solid var(--border); border-radius: 2px; color: var(--muted); letter-spacing: 0.05em; text-transform: uppercase; }
.tag.gold { border-color: var(--gold-dim); color: var(--gold); }

/* Footer */
footer { background: var(--bg2); border-top: 1px solid var(--border); padding: 2rem; text-align: center; font-family: var(--font-mono); font-size: 0.72rem; color: var(--muted); }
footer span { color: var(--gold); }

/* Fade-up */
.fade-up { opacity: 0; transform: translateY(24px); transition: opacity 0.6s ease, transform 0.6s ease; }
.fade-up.visible { opacity: 1; transform: none; }

/* Scrollbar */
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: var(--bg); }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--gold-dim); }

/* Divider */
.divider { border: none; border-top: 1px solid var(--border); margin: 3rem 0; }

/* Terminal block */
.terminal { background: var(--bg); border: 1px solid var(--border); border-radius: 6px; overflow: hidden; font-family: var(--font-mono); font-size: 0.82rem; }
.term-bar { background: var(--bg3); padding: 0.6rem 1rem; display: flex; align-items: center; gap: 0.5rem; border-bottom: 1px solid var(--border); }
.term-dot { width: 10px; height: 10px; border-radius: 50%; }
.term-dot.r { background: oklch(0.55 0.2 25); }
.term-dot.y { background: oklch(0.75 0.2 90); }
.term-dot.g { background: oklch(0.65 0.2 140); }
.term-title { font-size: 0.7rem; color: var(--muted); margin: 0 auto; }
