/* ── PAGE HEADER ── */
.page-header {
  padding: 5rem 2rem 3rem;
  background: var(--bg2);
  border-bottom: 1px solid var(--border);
  position: relative; overflow: hidden;
}
.page-header-bg {
  position: absolute; inset: 0;
  background-image: linear-gradient(var(--border) 1px, transparent 1px), linear-gradient(90deg, var(--border) 1px, transparent 1px);
  background-size: 48px 48px;
  opacity: 0.25;
  mask-image: linear-gradient(180deg, transparent, black 60%);
}
.page-header-inner { position: relative; max-width: var(--max-w); margin: 0 auto; }
.breadcrumb { font-family: var(--font-mono); font-size: 0.72rem; color: var(--muted); margin-bottom: 0.6rem; }
.breadcrumb a { color: var(--gold); text-decoration: none; }
.breadcrumb a:hover { text-decoration: underline; }
.project-status-badge {
  display: inline-flex; align-items: center; gap: 0.4rem;
  font-family: var(--font-mono); font-size: 0.68rem; text-transform: uppercase; letter-spacing: 0.1em;
  padding: 0.25rem 0.75rem;
  border-radius: 2px;
  margin-bottom: 1rem;
}
.status-active { background: oklch(0.72 0.17 155 / 0.12); color: var(--green); border: 1px solid oklch(0.52 0.14 155 / 0.4); }
.status-active::before { content: ''; width: 6px; height: 6px; border-radius: 50%; background: var(--green); animation: pulse 1.5s ease-in-out infinite; }
.status-complete { background: oklch(0.76 0.18 80 / 0.1); color: var(--gold); border: 1px solid var(--gold-dim); }
.status-wip { background: oklch(0.65 0.18 50 / 0.1); color: oklch(0.75 0.18 50); border: 1px solid oklch(0.5 0.15 50 / 0.4); }
@keyframes pulse { 0%,100% { opacity: 1; } 50% { opacity: 0.3; } }

.page-header h1 { font-family: var(--font-disp); font-size: clamp(2.8rem, 6vw, 5rem); line-height: 0.95; letter-spacing: 0.02em; max-width: 800px; }
.page-header h1 .accent { color: var(--gold); }
.page-header-sub { font-family: var(--font-mono); font-size: 0.85rem; color: var(--muted); margin-top: 0.75rem; max-width: 600px; }

.header-meta {
  display: flex; flex-wrap: wrap; gap: 2rem; margin-top: 2rem;
  padding-top: 1.5rem; border-top: 1px solid var(--border);
}
.meta-item { font-family: var(--font-mono); font-size: 0.78rem; }
.meta-label { color: var(--muted); font-size: 0.68rem; text-transform: uppercase; letter-spacing: 0.08em; display: block; margin-bottom: 0.2rem; }
.meta-val { color: var(--text); }
.meta-val a { color: var(--gold); text-decoration: none; }
.meta-val a:hover { text-decoration: underline; }

/* ── OVERVIEW ── */
.overview-grid {
  display: grid; grid-template-columns: 2fr 1fr; gap: 4rem; align-items: start;
}
.overview-body p { color: var(--muted); font-size: 0.97rem; line-height: 1.8; margin-bottom: 1rem; }
.overview-body p strong { color: var(--text); }
.overview-body p .accent { color: var(--gold); font-style: italic; }
.overview-body h3 { font-family: var(--font-disp); font-size: 1.6rem; color: var(--text); margin-top: 1.5rem; margin-bottom: 0.5rem; }

.sidebar { display: flex; flex-direction: column; gap: 1rem; }
.sidebar-card {
  background: var(--bg2); border: 1px solid var(--border); border-radius: 6px;
  padding: 1.25rem;
}
.sidebar-card h4 { font-family: var(--font-mono); font-size: 0.72rem; text-transform: uppercase; letter-spacing: 0.1em; color: var(--muted); margin-bottom: 0.85rem; }
.sidebar-tags { display: flex; flex-wrap: wrap; gap: 0.4rem; }
.sidebar-stat { display: flex; justify-content: space-between; align-items: center; padding: 0.5rem 0; border-bottom: 1px solid var(--border); font-family: var(--font-mono); font-size: 0.8rem; }
.sidebar-stat:last-child { border-bottom: none; }
.sidebar-stat-key { color: var(--muted); }
.sidebar-stat-val { color: var(--gold); font-weight: 700; }

/* ── CONTENT SECTION ── */
.content-section { background: var(--bg2); }
.content-body {
  max-width: 720px;
}
.content-body h3 { font-family: var(--font-disp); font-size: 1.8rem; color: var(--text); margin-bottom: 0.75rem; }
.content-body p { color: var(--muted); font-size: 0.95rem; line-height: 1.8; margin-bottom: 1rem; }
.content-body ul { list-style: none; display: flex; flex-direction: column; gap: 0.5rem; margin-bottom: 1rem; }
.content-body ul li { color: var(--muted); font-size: 0.93rem; line-height: 1.7; padding-left: 1.2rem; position: relative; }
.content-body ul li::before { content: '→'; position: absolute; left: 0; color: var(--gold); }
.content-body strong { color: var(--text); }

/* ── RESULTS ── */
.results-grid {
  display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 1rem;
  margin-top: 2rem;
}
.result-card {
  background: var(--bg); border: 1px solid var(--border); border-radius: 6px;
  padding: 1.5rem; text-align: center;
  transition: border-color 0.2s;
}
.result-card:hover { border-color: var(--gold-dim); }
.result-val { font-family: var(--font-disp); font-size: 2.8rem; color: var(--gold); line-height: 1; }
.result-label { font-family: var(--font-mono); font-size: 0.7rem; color: var(--muted); text-transform: uppercase; letter-spacing: 0.08em; margin-top: 0.35rem; }

/* ── IMAGE PLACEHOLDER ── */
.img-placeholder {
  background: var(--bg3); border: 1px solid var(--border); border-radius: 6px;
  height: 300px;
  display: flex; align-items: center; justify-content: center;
  font-family: var(--font-mono); font-size: 0.78rem; color: var(--muted);
  text-align: center; padding: 2rem;
}

/* ── NAV FOOTER ── */
.project-nav {
  display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 1rem;
  padding: 2rem; max-width: var(--max-w); margin: 0 auto;
  border-top: 1px solid var(--border);
}
.project-nav a {
  font-family: var(--font-mono); font-size: 0.78rem; color: var(--gold);
  text-decoration: none; letter-spacing: 0.06em; text-transform: uppercase;
  transition: opacity 0.2s;
}
.project-nav a:hover { opacity: 0.7; }
.project-nav-prev::before { content: '← '; }
.project-nav-next::after { content: ' →'; }

@media (max-width: 700px) {
  .overview-grid { grid-template-columns: 1fr; }
}

/* ── OMYA SHARED STYLES ── */
@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;500;700&family=Bebas+Neue&family=Inter:wght@400;500;600&display=swap');

:root {
  --bg:        oklch(0.11 0.015 252);
  --bg2:       oklch(0.15 0.015 252);
  --bg3:       oklch(0.19 0.015 252);
  --gold:      oklch(0.76 0.18 80);
  --gold-dim:  oklch(0.55 0.14 80);
  --navy:      oklch(0.27 0.09 248);
  --text:      oklch(0.91 0.01 252);
  --muted:     oklch(0.55 0.02 252);
  --green:     oklch(0.72 0.17 155);
  --border:    oklch(0.22 0.02 252);
  --font-mono: 'JetBrains Mono', monospace;
  --font-disp: 'Bebas Neue', sans-serif;
  --font-body: 'Inter', sans-serif;
  --max-w:     1100px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }

body {
  background: var(--bg);
  color: var(--text);
  font-family: var(--font-body);
  line-height: 1.6;
  overflow-x: hidden;
}

/* Scanlines */
body::before {
  content: '';
  position: fixed; inset: 0;
  background: repeating-linear-gradient(0deg, transparent, transparent 2px, oklch(0 0 0 / 0.04) 2px, oklch(0 0 0 / 0.04) 4px);
  pointer-events: none;
  z-index: 9999;
}

/* Nav */
nav {
  position: fixed; top: 0; left: 0; right: 0; z-index: 100;
  display: flex; align-items: center; justify-content: space-between;
  padding: 0 2.5rem; height: 60px;
  background: oklch(0.11 0.015 252 / 0.92);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--border);
}
.nav-logo { font-family: var(--font-disp); font-size: 1.4rem; letter-spacing: 0.04em; color: var(--gold); text-decoration: none; }
.nav-logo span { color: var(--text); }
.nav-links { display: flex; gap: 2rem; list-style: none; }
.nav-links a { font-family: var(--font-mono); font-size: 0.78rem; color: var(--muted); text-decoration: none; letter-spacing: 0.06em; text-transform: uppercase; transition: color 0.2s; }
.nav-links a:hover, .nav-links a.active { color: var(--gold); }

/* Page shell */
.page-wrap { padding-top: 60px; min-height: 100vh; }

/* Section */
.section { padding: 5rem 2rem; }
.section-inner { max-width: var(--max-w); margin: 0 auto; }
.section-label { font-family: var(--font-mono); font-size: 0.72rem; color: var(--green); letter-spacing: 0.14em; text-transform: uppercase; margin-bottom: 0.5rem; }
.section-label::before { content: '// '; }
.section-title { font-family: var(--font-disp); font-size: clamp(2.5rem, 5vw, 4rem); letter-spacing: 0.02em; line-height: 1; margin-bottom: 2.5rem; }
.section-title .accent { color: var(--gold); }

/* Buttons */
.btn { display: inline-block; padding: 0.65rem 1.6rem; font-family: var(--font-mono); font-size: 0.78rem; letter-spacing: 0.08em; text-transform: uppercase; text-decoration: none; border-radius: 3px; cursor: pointer; transition: all 0.2s; border: none; }
.btn-primary { background: var(--gold); color: oklch(0.11 0.015 252); font-weight: 700; }
.btn-primary:hover { background: oklch(0.82 0.18 80); transform: translateY(-2px); }
.btn-outline { background: transparent; color: var(--gold); border: 1px solid var(--gold); }
.btn-outline:hover { background: oklch(0.76 0.18 80 / 0.1); transform: translateY(-2px); }

/* Tags */
.tag { font-family: var(--font-mono); font-size: 0.65rem; padding: 0.2rem 0.55rem; background: var(--bg3); border: 1px solid var(--border); border-radius: 2px; color: var(--muted); letter-spacing: 0.05em; text-transform: uppercase; }
.tag.gold { border-color: var(--gold-dim); color: var(--gold); }

/* Footer */
footer { background: var(--bg2); border-top: 1px solid var(--border); padding: 2rem; text-align: center; font-family: var(--font-mono); font-size: 0.72rem; color: var(--muted); }
footer span { color: var(--gold); }

/* Fade-up */
.fade-up { opacity: 0; transform: translateY(24px); transition: opacity 0.6s ease, transform 0.6s ease; }
.fade-up.visible { opacity: 1; transform: none; }

/* Scrollbar */
::-webkit-scrollbar { width: 6px; }
::-webkit-scrollbar-track { background: var(--bg); }
::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--gold-dim); }

/* Divider */
.divider { border: none; border-top: 1px solid var(--border); margin: 3rem 0; }

/* Terminal block */
.terminal { background: var(--bg); border: 1px solid var(--border); border-radius: 6px; overflow: hidden; font-family: var(--font-mono); font-size: 0.82rem; }
.term-bar { background: var(--bg3); padding: 0.6rem 1rem; display: flex; align-items: center; gap: 0.5rem; border-bottom: 1px solid var(--border); }
.term-dot { width: 10px; height: 10px; border-radius: 50%; }
.term-dot.r { background: oklch(0.55 0.2 25); }
.term-dot.y { background: oklch(0.75 0.2 90); }
.term-dot.g { background: oklch(0.65 0.2 140); }
.term-title { font-size: 0.7rem; color: var(--muted); margin: 0 auto; }
.term-body { padding: 1.5rem; line-height: 2; }
.term-prompt { color: var(--green); }
.term-out { color: var(--muted); padding-left: 0.5rem; display: block; }
.term-key { color: var(--gold); }

